interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function expandRange(start: number, end: number, step: number, min: number, max: number): number[] {
  clamp(start, min, max);
  clamp(end,   min, max);
  if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
  if (step < 1)    throw new RangeError(`Step must be >= 1, got ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) values.push(i);
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */N or start-end/N
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step)) throw new SyntaxError(`Invalid step value: "${stepPart}"`);
    if (rangePart === "*") return expandRange(min, max, step, min, max);
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range in step: "${rangePart}"`);
    return expandRange(start, end, step, min, max);
  }

  // Wildcard
  if (segment === "*") return expandRange(min, max, 1, min, max);

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range: "${segment}"`);
    return expandRange(start, end, 1, min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron value: "${segment}"`);
  return [clamp(value, min, max)];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 cron fields, got ${fields.length}`);
  }

  return Object.fromEntries(
    FIELD_ORDER.map((name, i) => {
      const [min, max] = FIELD_RANGES[name];
      return [name, parseField(fields[i], min, max)];
    })
  ) as CronExpression;
}

