type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: "${stepStr}"`);
    const [from, to] = rangePart === "*" ? [min, max] : parseRangeBounds(rangePart, min, max);
    return rangeArray(from, to, step);
  }

  // Wildcard
  if (segment === "*") return rangeArray(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const [from, to] = parseRangeBounds(segment, min, max);
    return rangeArray(from, to);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron value: "${segment}"`);
  if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}-${max}]`);
  return [value];
}

function parseRangeBounds(segment: string, min: number, max: number): [number, number] {
  const parts = segment.split("-");
  if (parts.length !== 2) throw new Error(`Invalid range: "${segment}"`);
  const from = parseInt(parts[0], 10);
  const to   = parseInt(parts[1], 10);
  if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range bounds: "${segment}"`);
  if (from < min || to > max) throw new Error(`Range "${segment}" out of bounds [${min}-${max}]`);
  if (from > to) throw new Error(`Range start ${from} exceeds end ${to}`);
  return [from, to];
}

function parseField(expression: string, min: number, max: number): number[] {
  const values = new Set<number>();
  for (const segment of expression.split(",")) {
    for (const v of parseSegment(segment.trim(), min, max)) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${fields.length}`);
  }

  const fieldNames: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return fieldNames.reduce((acc, name, i) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(fields[i], min, max);
    return acc;
  }, {} as CronExpression);
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseRange(token: string, min: number, max: number): [number, number] {
  const [a, b] = token.split("-").map(Number);
  if (isNaN(a) || isNaN(b)) throw new Error(`Invalid range: "${token}"`);
  if (a < min || b > max) throw new Error(`Range "${token}" exceeds bounds [${min}, ${max}]`);
  if (a > b) throw new Error(`Range "${token}" start exceeds end`);
  return [a, b];
}

function parseToken(token: string, min: number, max: number): number[] {
  if (token.includes(",")) {
    const values = token.split(",").flatMap(t => parseToken(t.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: "${stepStr}"`);

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      [start, end] = parseRange(rangePart, min, max);
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: "${rangePart}"`);
      if (start < min || start > max) throw new Error(`Step base ${start} out of range [${min}, ${max}]`);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  if (token.includes("-")) {
    const [start, end] = parseRange(token, min, max);
    return range(start, end);
  }

  if (token === "*") {
    return range(min, max);
  }

  const n = parseInt(token, 10);
  if (isNaN(n)) throw new Error(`Invalid cron value: "${token}"`);
  if (n < min || n > max) throw new Error(`Value ${n} out of range [${min}, ${max}]`);
  return [n];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseToken(fields[i], min, max);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;

type FlattenedObject = Record<string, Primitive>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;
    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as Record<string, unknown>, flatKey, result);
    } else {
      result[flatKey] = value as Primitive;
    }
  }
  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);
    const start = left === "*" ? min : parseInt(left, 10);
    if (isNaN(start)) throw new Error(`Invalid step start: "${left}"`);
    const result: number[] = [];
    for (let i = start; i <= max; i += step) result.push(i);
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${segment}"`);
    if (start > end) throw new Error(`Range start > end: "${segment}"`);
    return range(start, end);
  }

  // List: a,b,c
  if (segment.includes(",")) {
    const values = segment.split(",").flatMap(s => parseSegment(s.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron value: "${segment}"`);
  return [value];
}

function validateValues(values: number[], min: number, max: number, field: CronField): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new RangeError(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
  return values;
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${fields.length}: "${expression}"`);
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    const [min, max] = FIELD_RANGES[field];
    const raw = parseSegment(fields[i], min, max);
    result[field] = validateValues([...new Set(raw)].sort((a, b) => a - b), min, max, field);
  }

  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronField = keyof CronExpression;

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function range(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${field}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        assertInRange(lo, min, max, field);
        assertInRange(hi, min, max, field);
        if (lo > hi) throw new RangeError(`Invalid range "${rangePart}" in field "${field}"`);
        start = lo;
        end = hi;
      } else {
        const val = parseInt(rangePart, 10);
        assertInRange(val, min, max, field);
        start = val;
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [loStr, hiStr] = segment.split("-");
    const lo = parseInt(loStr, 10);
    const hi = parseInt(hiStr, 10);
    if (isNaN(lo) || isNaN(hi)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    assertInRange(lo, min, max, field);
    assertInRange(hi, min, max, field);
    if (lo > hi) throw new RangeError(`Invalid range "${segment}" in field "${field}"`);
    return range(lo, hi);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(token: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list
  const segments = token.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), field)) {
      values.add(v);
    }
  }

  return clamp([...values].sort((a, b) => a - b), min, max);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${tokens.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(tokens[i], field);
  }

  return result;
}

