}

export default function deepMerge<T extends PlainObject>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source) as Array<keyof typeof source>) {
    const sourceVal = source[key];
    const targetVal = result[key as string];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key as string] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key as string] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key as string] = sourceVal;
    }
  }

  return result as T;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (from: number, to: number): number[] =>
  Array.from({ length: to - from + 1 }, (_, i) => from + i);

const parseField = (expr: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Comma-separated list — recurse on each segment
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") return range(min, max);

  // Step value: */N or start-end/N
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value in expression: "${expr}"`);
    }

    const base = rangePart === "*" ? range(min, max) : parseField(rangePart, config);
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new RangeError(`Invalid range expression: "${expr}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in: "${expr}"`);
    }
    if (start < min || end > max) {
      throw new RangeError(
        `Range ${start}-${end} out of bounds [${min}-${max}] in: "${expr}"`
      );
    }

    return range(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);

  if (isNaN(value)) {
    throw new TypeError(`Unrecognised cron token: "${expr}"`);
  }
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of bounds [${min}-${max}]`);
  }

  return [value];
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fieldKeys = Object.keys(FIELD_CONFIGS) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return Object.fromEntries(
    fieldKeys.map((key, i) => [key, parseField(exprs[i], FIELD_CONFIGS[key])])
  ) as CronFields;
};

export default parseCron;

