      const [startStr, endStr] = rangeOrWild.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end) || start < min || end > max || start > end) {
        throw new Error(`Invalid range in step expression: ${rangeOrWild}`);
      }
      base = range(start, end);
    } else {
      const start = parseInt(rangeOrWild, 10);
      if (isNaN(start) || start < min || start > max) {
        throw new Error(`Invalid start in step expression: ${rangeOrWild}`);
      }
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(`Range ${field} out of bounds [${min}-${max}]`);
    }
    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid field value: ${field}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  }
  return [value];
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const [minuteConfig, hourConfig, domConfig, monthConfig, dowConfig] = FIELD_CONFIGS;

  return {
    minute: parseField(minuteField, minuteConfig),
    hour: parseField(hourField, hourConfig),
    dayOfMonth: parseField(domField, domConfig),
    month: parseField(monthField, monthConfig),
    dayOfWeek: parseField(dowField, dowConfig),
