export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseField(expr: string, min: number, max: number): number[] {
  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step: */n or start/n
  if (expr.includes("/")) {
    const [base, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}"`);
    }
    const [from, to] = base === "*" ? [min, max] : (() => {
      const parts = base.split("-").map((p) => parseInt(p, 10));
      if (parts.length === 2) return [parts[0], parts[1]] as [number, number];
      return [parseInt(base, 10), max] as [number, number];
    })();
    clamp(from, min, max);
    clamp(to, min, max);
    const result: number[] = [];
    for (let i = from; i <= to; i += step) result.push(i);
    return result;
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [fromStr, toStr] = expr.split("-");
    const from = clamp(parseInt(fromStr, 10), min, max);
    const to   = clamp(parseInt(toStr,   10), min, max);
    return range(from, to);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron field: "${expr}"`);
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fields[i], min, max);
  }

  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function expandRange(start: number, end: number, step = 1): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  if (step < 1)    throw new RangeError(`Invalid step: ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) values.push(i);
  return values;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  const assertInRange = (n: number) => {
    if (n < min || n > max)
      throw new RangeError(`Value ${n} out of range [${min}-${max}] for field "${field}"`);
    return n;
  };

  // Wildcard: *
  if (segment === "*") return expandRange(min, max);

  // Step on wildcard: */n
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step)) throw new SyntaxError(`Invalid step in "${segment}"`);
    return expandRange(min, max, step);
  }

  // Range with optional step: a-b or a-b/n
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr]    = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    const step  = stepPart ? parseInt(stepPart, 10) : 1;
    if (isNaN(start) || isNaN(end) || isNaN(step))
      throw new SyntaxError(`Invalid range expression "${segment}"`);
    assertInRange(start);
    assertInRange(end);
    return expandRange(start, end, step);
  }

  // Plain number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new SyntaxError(`Invalid value "${segment}" for field "${field}"`);
  return [assertInRange(n)];
}

function parseField(expr: string, field: CronField): number[] {
  // Comma-separated list
  const segments = expr.split(",");
  const values = new Set<number>();
  for (const seg of segments) {
    for (const v of parseSegment(seg.trim(), field)) values.add(v);
  }
  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new SyntaxError(`Expected 5 fields, got ${parts.length}: "${expression}"`);

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => [field, parseField(parts[i], field)])
  ) as CronExpression;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(obj: NestedObject, prefix = "", result: FlatObject = {}): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive | Array<unknown>;
    }
  }
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface CronExpression {
  minute: number[];
  hour: number[];
