const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

const clamp = (values: number[], min: number, max: number, field: string): number[] => {
  const invalid = values.filter(v => v < min || v > max);
  if (invalid.length > 0) {
    throw new RangeError(`${field}: value(s) ${invalid.join(", ")} out of range [${min}, ${max}]`);
  }
  return [...new Set(values)].sort((a, b) => a - b);
};

const range = (start: number, end: number): number[] => {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
};

const parseField = (token: string, field: FieldName): number[] => {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part
  if (token.includes(",")) {
    const values = token.split(",").flatMap(part => parseField(part.trim(), field));
    return clamp(values, min, max, field);
  }

  // Step: */n or start-end/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new RangeError(`${field}: invalid step "${stepStr}"`);

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      base = range(s, e);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new SyntaxError(`${field}: invalid step base "${rangePart}"`);
      base = range(start, max);
    }

    const stepped = base.filter((_, i) => i % step === 0);
    return clamp(stepped, min, max, field);
  }

  // Wildcard
  if (token === "*") {
    return range(min, max);
  }

  // Range: start-end
  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) throw new SyntaxError(`${field}: invalid range "${token}"`);
    const [s, e] = parts.map(Number);
    if (isNaN(s) || isNaN(e)) throw new SyntaxError(`${field}: invalid range "${token}"`);
    return clamp(range(s, e), min, max, field);
  }

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num)) throw new SyntaxError(`${field}: unrecognized token "${token}"`);
  return clamp([num], min, max, field);
};

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}: "${expression}"`);
