    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${expr}" for ${field}`);
    if (start > end) throw new Error(`Range start ${start} > end ${end} for ${field}`);
    if (start < min || end > max) throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}] for ${field}`);
    return range(start, end);
