interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<keyof CronFields, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, { min, max }: FieldRange, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, range: FieldRange, field: string): number[] {
  const { min, max } = range;

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in segment "${segment}" for field "${field}"`);
    }

    let start: number;
    let end: number;

    if (left === "*") {
      start = min;
      end = max;
    } else if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      start = parseInt(startStr, 10);
      end   = parseInt(endStr,   10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range in segment "${segment}" for field "${field}"`);
      }
      assertInRange(start, range, field);
      assertInRange(end,   range, field);
      if (start > end) {
        throw new RangeError(`Range start ${start} > end ${end} in field "${field}"`);
      }
    } else {
      start = parseInt(left, 10);
      if (isNaN(start)) {
        throw new SyntaxError(`Invalid step expression "${segment}" for field "${field}"`);
      }
      assertInRange(start, range, field);
      end = max;
    }

    return rangeArray(start, end, step);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" for field "${field}"`);
    }
    assertInRange(start, range, field);
    assertInRange(end,   range, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} > end ${end} in field "${field}"`);
    }
    return rangeArray(start, end);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").map((part) => {
      const v = parseInt(part.trim(), 10);
      if (isNaN(v)) {
        throw new SyntaxError(`Invalid value "${part}" in list for field "${field}"`);
      }
      assertInRange(v, range, field);
      return v;
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" for field "${field}"`);
  }
  assertInRange(value, range, field);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${parts.length}: "${expression}"`
    );
  }

  return FIELD_ORDER.reduce((acc, field, index) => {
    acc[field] = parseSegment(parts[index], FIELD_RANGES[field], field);
    return acc;
  }, {} as CronFields);
}

