type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), field));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return clamp(unique, min, max);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field "${field}": ${expr}`);
    }
    const base = rangeExpr === "*" ? range(min, max) : parseField(rangeExpr, field);
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range in field "${field}": ${expr}`);
    }
    const values = range(start, end);
    const clamped = clamp(values, min, max);
    if (clamped.length === 0) {
      throw new Error(`Range out of bounds for field "${field}": ${expr} (valid: ${min}-${max})`);
    }
    return clamped;
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid value in field "${field}": ${expr}`);
  }
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of range for field "${field}" (valid: ${min}-${max})`);
  }
  return [num];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronExpression;
  for (let i = 0; i < fields.length; i++) {
    result[fields[i]] = parseField(parts[i], fields[i]);
  }

  return result;
}

