function parseField(field: string, min: number, max: number): number[] {
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part, min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value: "${stepStr}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      [rangeMin, rangeMax] = rangePart.split("-").map(Number);
    } else {
      rangeMin = parseInt(rangePart, 10);
      rangeMax = max;
    }

    if (isNaN(rangeMin) || isNaN(rangeMax)) {
      throw new RangeError(`Invalid range in step expression: "${field}"`);
    }
    if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
      throw new RangeError(
        `Range "${field}" out of bounds [${min}-${max}]`
      );
    }

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) result.push(i);
    return result;
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new RangeError(`Invalid range: "${field}"`);
    }
    if (start > end || start < min || end > max) {
      throw new RangeError(
        `Range "${field}" out of bounds [${min}-${max}]`
      );
    }
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  if (field === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new TypeError(`Unrecognised cron token: "${field}"`);
  }
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of bounds [${min}-${max}]`
    );
  }
  return [value];
}

