  }

  // Wildcard with optional step: * or */N
  if (token.startsWith("*")) {
    if (token === "*") return rangeArray(min, max);
    if (token.startsWith("*/")) {
      const step = parseInt(token.slice(2), 10);
      if (isNaN(step) || step < 1) throw new Error(`Invalid step in token: "${token}"`);
      return rangeArray(min, max, step);
    }
    throw new Error(`Invalid wildcard token: "${token}"`);
  }

  // Range with optional step: A-B or A-B/N
  if (token.includes("-")) {
    const [rangePart, stepPart] = token.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step) || step < 1)
      throw new Error(`Invalid range token: "${token}"`);
    if (start < min || end > max || start > end)
      throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}]`);

    return rangeArray(start, end, step);
  }

  // Step on a number base: N/S
  if (token.includes("/")) {
    const [baseStr, stepStr] = token.split("/");
    const base = parseInt(baseStr, 10);
    const step = parseInt(stepStr, 10);
    if (isNaN(base) || isNaN(step) || step < 1)
      throw new Error(`Invalid step token: "${token}"`);
    if (base < min || base > max)
      throw new Error(`Value ${base} out of bounds [${min}-${max}]`);
    return rangeArray(base, max, step);
  }

  // Single numeric value
  const value = parseInt(token, 10);
  if (isNaN(value)) throw new Error(`Invalid token: "${token}"`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  return [value];
}

