  const [minuteToken, hourToken, domToken, monthToken, dowToken] = parts;
  const fields = Object.keys(FIELD_CONFIGS) as Array<keyof CronExpression>;
  const tokens = [minuteToken, hourToken, domToken, monthToken, dowToken];

  const result = {} as CronExpression;
  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    result[field] = parseField(tokens[i], FIELD_CONFIGS[field]);
  }

  return result;
}

