type CronField = {
  min: number;
  max: number;
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELDS: [keyof ParsedCron, CronField][] = [
  ["minute", { min: 0, max: 59 }],
  ["hour", { min: 0, max: 23 }],
  ["dayOfMonth", { min: 1, max: 31 }],
  ["month", { min: 1, max: 12 }],
  ["dayOfWeek", { min: 0, max: 6 }],
];

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const { min, max } = field;

  // Comma-separated list
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      end = max;
    }

    if (start < min || end > max || start > end) {
      throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}]`);
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range: ${expr}`);
    }
    if (start < min || end > max) {
      throw new Error(`Range ${start}-${end} out of bounds [${min}-${max}]`);
    }
    return range(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${expr}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  }
  return [value];
}

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELDS.length; i++) {
    const [name, field] = FIELDS[i];
    result[name] = parseField(parts[i], field);
  }

  return result;
}

