  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const allValues = range(min, max);

  // Wildcard
  if (field === "*") return allValues;

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepStr}`);

    let base: number[];
    if (rangePart === "*") {
      base = allValues;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${rangePart}`);
      if (start < min || end > max || start > end)
        throw new Error(`Range out of bounds: ${rangePart} (valid: ${min}-${max})`);
      base = range(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: ${rangePart}`);
      if (start < min || start > max)
        throw new Error(`Value out of bounds: ${start} (valid: ${min}-${max})`);
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds: ${field} (valid: ${min}-${max})`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${field}`);
  if (value < min || value > max)
    throw new Error(`Value out of bounds: ${value} (valid: ${min}-${max})`);
  return [value];
}

