  return value;
};

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = clamp(s, min, max);
        end = clamp(e, min, max);
        if (start > end) throw new RangeError(`Invalid range: ${rangePart}`);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Invalid range: ${segment}`);
    return range(start, end);
  }

  // Comma-separated list: 1,3,5
  if (segment.includes(",")) {
    return [...new Set(
      segment.split(",").map((s) => clamp(parseInt(s.trim(), 10), min, max))
    )].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron segment: "${segment}"`);
  return [clamp(value, min, max)];
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minutePart, hourPart, domPart, monthPart, dowPart] = parts;
  const fieldOrder = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
  const fieldParts = [minutePart, hourPart, domPart, monthPart, dowPart];

  const result = {} as CronFields;

  for (let i = 0; i < fieldOrder.length; i++) {
    const key = fieldOrder[i];
    result[key] = parseSegment(fieldParts[i], FIELD_CONFIGS[key]);
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  result.dayOfWeek = [...new Set(
    result.dayOfWeek.map((d) => (d === 7 ? 0 : d))
  )].sort((a, b) => a - b);

  return result;
};

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_ORDER: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap(part => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in "${expr}" for ${field}`);
    return range(min, max).filter(v => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in "${expr}" for ${field}`);
    const [start, end] = rangePart.includes("-")
      ? rangePart.split("-").map(n => parseInt(n, 10))
      : [parseInt(rangePart, 10), max];
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in "${expr}" for ${field}`);
    return range(start, end).filter(v => (v - start) % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range "${expr}" for ${field}`);
    if (start > end) throw new Error(`Range start > end in "${expr}" for ${field}`);
    if (start < min || end > max) throw new Error(`Range "${expr}" out of bounds [${min}-${max}] for ${field}`);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${expr}" for ${field}`);
  if (value < min || value > max) throw new Error(`Value ${value} out of bounds [${min}-${max}] for ${field}`);
  return [value];
}

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => [field, parseField(parts[i], field)])
  ) as ParsedCron;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  const output = { ...target } as PlainObject;

  for (const key of Object.keys(source)) {
    const targetVal = output[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
}

export default deepMerge;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangeOrStar, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step in "${segment}"`);

    let start: number;
    let end: number;

    if (rangeOrStar === "*") {
      start = min;
      end = max;
    } else if (rangeOrStar.includes("-")) {
      const [s, e] = rangeOrStar.split("-").map(Number);
      start = clamp(s, min, max);
      end = clamp(e, min, max);
      if (start > end) throw new Error(`Invalid range "${rangeOrStar}"`);
    } else {
      start = clamp(parseInt(rangeOrStar, 10), min, max);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Invalid range "${segment}"`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value "${segment}" for field ${field}`);
  return [clamp(value, min, max)];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), field)) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month:      parseField(monthExpr, "month"),
    dayOfWeek:  parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }

  return result;
}

