type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, readonly [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 6],
};

function assertInRange(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(expr: string, min: number, max: number): number[] {
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/", 2);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangeExpr === "*") {
      start = min;
      end = max;
    } else if (rangeExpr.includes("-")) {
      const [s, e] = rangeExpr.split("-", 2).map(Number);
      start = assertInRange(s, min, max);
      end   = assertInRange(e, min, max);
    } else {
      start = assertInRange(parseInt(rangeExpr, 10), min, max);
      end = max;
    }

    if (start > end) throw new Error(`Invalid range start > end in: "${expr}"`);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-", 2);
    const start = assertInRange(parseInt(startStr, 10), min, max);
    const end   = assertInRange(parseInt(endStr,   10), min, max);
    if (start > end) throw new Error(`Invalid range start > end in: "${expr}"`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  const val = parseInt(expr, 10);
  if (isNaN(val)) throw new Error(`Invalid cron token: "${expr}"`);
  return [assertInRange(val, min, max)];
}

function parseField(expr: string, min: number, max: number): number[] {
  const raw = expr.includes(",")
    ? expr.split(",").flatMap(part => parseSegment(part.trim(), min, max))
    : parseSegment(expr.trim(), min, max);

  return [...new Set(raw)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Cron expression must have exactly 5 fields, got ${parts.length}`);
  }

  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return fields.reduce((acc, field, i) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = parseField(parts[i], min, max);
    return acc;
  }, {} as ParsedCron);
}

