export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: Array<keyof CronFields> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function range(min: number, max: number, step = 1): number[] {
  const values: number[] = [];
  for (let i = min; i <= max; i += step) {
    values.push(i);
  }
  return values;
}

function assertInRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig, field: string): number[] {
  const { min, max } = config;

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangeStr, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value in segment "${segment}" for field "${field}"`);
    }
    if (rangeStr === "*") {
      return range(min, max, step);
    }
    if (rangeStr.includes("-")) {
      const [startStr, endStr] = rangeStr.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range in segment "${segment}" for field "${field}"`);
      }
      assertInRange(start, min, max, field);
      assertInRange(end, min, max, field);
      if (start > end) {
        throw new RangeError(`Range start ${start} exceeds end ${end} in field "${field}"`);
      }
      return range(start, end, step);
    }
    throw new SyntaxError(`Invalid step expression "${segment}" for field "${field}"`);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range in segment "${segment}" for field "${field}"`);
    }
    assertInRange(start, min, max, field);
    assertInRange(end, min, max, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in field "${field}"`);
    }
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" for field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, config: FieldConfig, field: string): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), config, field);
    for (const v of parsed) {
      // Normalize dayOfWeek: treat 7 as 0 (both = Sunday)
      values.add(field === "dayOfWeek" && v === 7 ? 0 : v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${parts.length}: "${expression}"`
    );
  }

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => [
      field,
      parseField(parts[i], FIELD_CONFIGS[field], field),
    ])
  ) as CronFields;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

export default function flattenObject(
