export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) => parseField(part.trim(), config));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Wildcard with optional step: * or */n
  if (field.startsWith("*")) {
    if (field === "*") return rangeArray(min, max);
    if (field.startsWith("*/")) {
      const step = parseInt(field.slice(2), 10);
      if (isNaN(step) || step < 1) throw new Error(`Invalid step value in field: "${field}"`);
      return rangeArray(min, max, step);
    }
    throw new Error(`Invalid wildcard expression: "${field}"`);
  }

  // Range with optional step: n-m or n-m/s
  if (field.includes("-")) {
    const [rangePart, stepPart] = field.split("/");
    const [startStr, endStr] = rangePart!.split("-");
    const start = parseInt(startStr!, 10);
    const end = parseInt(endStr!, 10);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step))
      throw new Error(`Invalid range expression: "${field}"`);
    if (start < min || end > max)
      throw new Error(`Range "${field}" out of bounds [${min}-${max}]`);
    if (start > end)
      throw new Error(`Range start (${start}) exceeds end (${end}) in field: "${field}"`);
    if (step < 1)
      throw new Error(`Step must be >= 1 in field: "${field}"`);

    return rangeArray(start, end, step);
  }

  // Step on a specific start without wildcard: n/s
  if (field.includes("/")) {
    const [startStr, stepStr] = field.split("/");
    const start = parseInt(startStr!, 10);
    const step = parseInt(stepStr!, 10);

    if (isNaN(start) || isNaN(step)) throw new Error(`Invalid step expression: "${field}"`);
    if (start < min || start > max)
      throw new Error(`Value ${start} out of bounds [${min}-${max}]`);
    if (step < 1) throw new Error(`Step must be >= 1 in field: "${field}"`);

    return rangeArray(start, max, step);
  }

  // Single numeric value
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: "${field}"`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);

  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}. Input: "${expression}"`
    );
  }

  const [minutePart, hourPart, domPart, monthPart, dowPart] = parts as [
    string, string, string, string, string
  ];

  return {
    minute:     parseField(minutePart, FIELD_CONFIGS.minute),
    hour:       parseField(hourPart,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domPart,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthPart,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowPart,    FIELD_CONFIGS.dayOfWeek),
  };
}

type CronObject = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronObject, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  const fullRange = range(min, max);

  if (field === "*") return fullRange;

  if (field.startsWith("*/")) {
    const step = parseInt(field.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${field}`);
    return fullRange.filter((v) => (v - min) % step === 0);
  }

  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${field}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds: ${field} (valid: ${min}-${max})`);
    return range(start, end);
  }

  if (field.includes("/")) {
    const [rangeOrWild, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${field}`);
    const base = parseField(rangeOrWild, min, max);
    return base.filter((v, i) => i % step === 0);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid cron field value: ${field}`);
  if (num < min || num > max)
    throw new Error(`Value ${num} out of range (valid: ${min}-${max})`);
  return [num];
};

const parseCron = (expression: string): CronObject => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const keys = Object.keys(FIELD_RANGES) as (keyof CronObject)[];

  return keys.reduce((acc, key, i) => {
    const [min, max] = FIELD_RANGES[key];
    acc[key] = parseField(fields[i], min, max);
    return acc;
  }, {} as CronObject);
};

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function expandField(expr: string, min: number, max: number): number[] {
  // Comma-separated list
  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap(part => expandField(part.trim(), min, max))
      .filter((v, i, a) => a.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Step: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        [start, end] = parseRange(rangePart, min, max);
      } else {
        start = parseNumber(rangePart, min, max);
        end = max;
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [start, end] = parseRange(expr, min, max);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Wildcard
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Single number
  return [parseNumber(expr, min, max)];
}

function parseRange(expr: string, min: number, max: number): [number, number] {
  const parts = expr.split("-");
  if (parts.length !== 2) throw new Error(`Invalid range: "${expr}"`);
  const start = parseNumber(parts[0], min, max);
  const end = parseNumber(parts[1], min, max);
  if (start > end) throw new Error(`Range start exceeds end: "${expr}"`);
  return [start, end];
}

function parseNumber(expr: string, min: number, max: number): number {
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Expected a number, got "${expr}"`);
  if (n < min || n > max) throw new Error(`Value ${n} out of range [${min}, ${max}]`);
  return n;
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const keys = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return keys.reduce((acc, key, i) => {
    const [min, max] = FIELD_RANGES[key];
    acc[key] = expandField(exprs[i], min, max);
    return acc;
  }, {} as CronFields);
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(obj: NestedObject, prefix = ""): FlatObject {
  return Object.entries(obj).reduce<FlatObject>((acc, [key, value]) => {
    const flatKey = prefix ? `${prefix}.${key}` : key;
    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      Object.assign(acc, flattenObject(value as NestedObject, flatKey));
    } else {
      acc[flatKey] = value as Primitive;
    }
    return acc;
  }, {});
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

const FIELD_NAMES: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function rangeArray(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseField(raw: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part
  if (raw.includes(",")) {
    const values = raw
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (raw === "*") return rangeArray(min, max);

  // Step: */n or base/n
  if (raw.includes("/")) {
    const [basePart, stepPart] = raw.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) throw new SyntaxError(`Invalid step value in "${raw}"`);

    const base = basePart === "*" ? rangeArray(min, max) : parseField(basePart, field);
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: a-b
  if (raw.includes("-")) {
    const [fromStr, toStr] = raw.split("-");
    const from = parseInt(fromStr, 10);
    const to   = parseInt(toStr,   10);
    if (isNaN(from) || isNaN(to)) throw new SyntaxError(`Invalid range "${raw}"`);
    assertInRange(from, min, max, field);
    assertInRange(to,   min, max, field);
    return rangeArray(from, to);
  }

  // Single number
  const value = parseInt(raw, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid value "${raw}" in field "${field}"`);
  assertInRange(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): ParsedCron {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  return Object.fromEntries(
    FIELD_NAMES.map((field, i) => [field, parseField(parts[i], field)])
  ) as ParsedCron;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? { ...source } : source) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  const output = { ...target } as PlainObject;

  for (const key of Object.keys(source)) {
    const targetVal = output[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(obj: NestedObject, prefix = "", result: FlatObject = {}): FlatObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];
    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }
  return result;
}

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELDS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
] as const;

function range(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function validateBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`${context}: ${value} is out of bounds [${min}, ${max}]`);
  }
}

function parseSegment(expr: string, min: number, max: number): number[] {
  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/", 2);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new TypeError(`Invalid step in "${expr}"`);

    let start = min;
    let end = max;

    if (rangeExpr !== "*") {
      if (rangeExpr.includes("-")) {
        const [s, e] = rangeExpr.split("-", 2).map(Number);
        validateBounds(s, min, max, `step range start in "${expr}"`);
        validateBounds(e, min, max, `step range end in "${expr}"`);
        [start, end] = [s, e];
      } else {
        start = parseInt(rangeExpr, 10);
        validateBounds(start, min, max, `step start in "${expr}"`);
      }
    }

    return range(start, end, step);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-", 2);
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new TypeError(`Invalid range "${expr}"`);
    if (start > end) throw new RangeError(`Range start exceeds end in "${expr}"`);
    validateBounds(start, min, max, `range start in "${expr}"`);
    validateBounds(end, min, max, `range end in "${expr}"`);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new TypeError(`Invalid value "${expr}"`);
  validateBounds(value, min, max, `value "${expr}"`);
  return [value];
}

function parseField(expr: string, min: number, max: number): number[] {
  if (!expr.includes(",")) return parseSegment(expr, min, max);

  const values = expr.split(",").flatMap(part => parseSegment(part.trim(), min, max));
  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${parts.length}: "${expression}"`);
  }

  const [minute, hour, dayOfMonth, month, dayOfWeek] = FIELDS.map(
    ({ name, min, max }, i) => {
      try {
        return parseField(parts[i], min, max);
      } catch (err) {
        throw new Error(`Invalid "${name}" field ("${parts[i]}"): ${(err as Error).message}`);
      }
    }
  );

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldMeta {
  min: number;
  max: number;
}

const FIELD_META: Record<keyof CronSchedule, FieldMeta> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (from: number, to: number, step = 1): number[] => {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
};

const parseField = (expr: string, meta: FieldMeta): number[] => {
  const { min, max } = meta;

  // Comma-separated list — recurse on each part and flatten
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), meta));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") return range(min, max);

  // Step value: */N or a-b/N
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step in: "${expr}"`);

    const [from, to] =
      rangePart === "*"
        ? [min, max]
        : (() => {
            const [a, b] = rangePart.split("-").map(Number);
            return [a, b];
          })();

    validateRange(from, to, min, max, expr);
    return range(from, to, step);
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [a, b] = expr.split("-").map(Number);
    if (isNaN(a) || isNaN(b)) throw new Error(`Invalid range: "${expr}"`);
    validateRange(a, b, min, max, expr);
    return range(a, b);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid value: "${expr}"`);
  if (n < min || n > max)
    throw new Error(`Value ${n} out of bounds [${min}-${max}]: "${expr}"`);
  return [n];
};

const validateRange = (
  from: number,
  to: number,
  min: number,
  max: number,
  expr: string,
): void => {
  if (isNaN(from) || isNaN(to))
    throw new Error(`Invalid range values in: "${expr}"`);
  if (from > to)
    throw new Error(`Range start exceeds end in: "${expr}"`);
  if (from < min || to > max)
    throw new Error(`Range [${from}-${to}] out of bounds [${min}-${max}]: "${expr}"`);
};

const parseCron = (expression: string): CronSchedule => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const keys = Object.keys(FIELD_META) as (keyof CronSchedule)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return Object.fromEntries(
    keys.map((key, i) => [key, parseField(exprs[i], FIELD_META[key])]),
  ) as CronSchedule;
};

export default parseCron;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;

type FlattenedObject = Record<string, Primitive>;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: FlattenedObject = {}
): FlattenedObject {
  for (const key of Object.keys(obj)) {
    const value = obj[key];
    const dotKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, dotKey, result);
    } else {
      result[dotKey] = value as Primitive;
    }
  }

  return result;
}

