type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(values: number[], min: number, max: number): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new RangeError(`Value ${v} is outside valid range [${min}, ${max}]`);
    }
  }
  return values;
}

function parseRange(expr: string): [number, number] {
  const [startStr, endStr] = expr.split("-");
  const start = parseInt(startStr, 10);
  const end = parseInt(endStr, 10);
  if (isNaN(start) || isNaN(end) || start > end) {
    throw new SyntaxError(`Invalid range expression: "${expr}"`);
  }
  return [start, end];
}

function expand(from: number, to: number, step: number): number[] {
  const values: number[] = [];
  for (let i = from; i <= to; i += step) values.push(i);
  return values;
}

function parseSegment(expr: string, min: number, max: number): number[] {
  if (expr === "*") {
    return expand(min, max, 1);
  }

  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);
    }
    const [from, to] = rangeExpr === "*" ? [min, max] : parseRange(rangeExpr);
    return assertInRange(expand(from, to, step), min, max);
  }

  if (expr.includes("-")) {
    const [from, to] = parseRange(expr);
    return assertInRange(expand(from, to, 1), min, max);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid cron value: "${expr}"`);
  }
  return assertInRange([value], min, max);
}

function parseField(expr: string, min: number, max: number): number[] {
  if (!expr.includes(",")) {
    return parseSegment(expr, min, max);
  }

  const values = expr
    .split(",")
    .flatMap((part) => parseSegment(part.trim(), min, max));

  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const fieldNames: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  return fieldNames.reduce((acc, name, i) => {
    const { min, max } = FIELD_RANGES[name];
    acc[name] = parseField(fields[i], min, max);
    return acc;
  }, {} as CronExpression);
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

