type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function rangeArray(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function clampValues(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseField(token: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Handle comma-separated list first
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (token === "*") {
    return rangeArray(min, max);
  }

  // Step value: */n or range/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field "${field}": ${token}`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = rangeArray(min, max);
    } else if (rangePart.includes("-")) {
      base = parseField(rangePart, field);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base in field "${field}": ${token}`);
      base = rangeArray(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: n-m
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end) || start > end) {
      throw new Error(`Invalid range in field "${field}": ${token}`);
    }

    const values = rangeArray(start, end);
    const clamped = clampValues(values, min, max);

    if (clamped.length === 0) {
      throw new Error(`Range out of bounds in field "${field}": ${token}`);
    }

    return clamped;
  }

  // Plain number
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value in field "${field}": ${token}`);
  }

  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}-${max}] for field "${field}"`
    );
  }

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (field === "dayOfWeek" && value === 7) {
    return [0];
  }

  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = parts;
  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];
  const tokens = [minuteToken, hourToken, domToken, monthToken, dowToken];

  const parsed = fields.reduce(
    (acc, field, i) => {
      acc[field] = [...new Set(parseField(tokens[i], field))].sort(
        (a, b) => a - b
      );
      return acc;
    },
    {} as CronExpression
  );

  return parsed;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, readonly [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

const FIELD_ORDER: FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function parseSegment(segment: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of segment.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) values.add(i);
      continue;
    }

    if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (!Number.isInteger(step) || step <= 0) {
        throw new RangeError(`Invalid step value in "${part}"`);
      }
      for (let i = min; i <= max; i += step) values.add(i);
      continue;
    }

    if (part.includes("-")) {
      const [rawStart, rawEnd] = part.split("-");
      const start = parseInt(rawStart, 10);
      const end   = parseInt(rawEnd,   10);
      if (!Number.isInteger(start) || !Number.isInteger(end)) {
        throw new TypeError(`Invalid range "${part}"`);
      }
      if (start > end) {
        throw new RangeError(`Range start exceeds end in "${part}"`);
      }
      if (start < min || end > max) {
        throw new RangeError(`Range "${part}" outside valid bounds [${min}, ${max}]`);
      }
      for (let i = start; i <= end; i++) values.add(i);
      continue;
    }

    const value = parseInt(part, 10);
    if (!Number.isInteger(value)) {
      throw new TypeError(`Invalid value "${part}"`);
    }
    if (value < min || value > max) {
      throw new RangeError(`Value ${value} outside valid bounds [${min}, ${max}]`);
    }
    values.add(value);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const segments = expression.trim().split(/\s+/);

  if (segments.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields; got ${segments.length}: "${expression}"`
    );
  }

  return Object.fromEntries(
    FIELD_ORDER.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, parseSegment(segments[i], min, max)];
    })
  ) as CronExpression;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    const [start, end] = rangePart.includes("-")
      ? rangePart.split("-").map(Number)
      : [parseInt(rangePart, 10), max];
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    return range(start, end).filter((v) => (v - start) % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    if (start > end) throw new Error(`Range start > end in field "${field}": ${expr}`);
    if (start < min || end > max)
      throw new Error(`Range out of bounds in field "${field}": ${expr} (valid: ${min}-${max})`);
    return range(start, end);
  }

  if (expr === "*") {
    return range(min, max);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value in field "${field}": ${expr}`);
  if (value < min || value > max)
    throw new Error(`Value out of bounds in field "${field}": ${value} (valid: ${min}-${max})`);
  return [value];
}

export default function parseCron(expression: string): CronResult {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);
  }

  const fields: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return fields.reduce((acc, field, i) => {
    acc[field] = parseField(parts[i], field);
    return acc;
  }, {} as CronResult);
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  const output = { ...target } as PlainObject;

  for (const key of Object.keys(source)) {
    const targetVal = output[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      output[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      output[key] = deepMerge(targetVal, sourceVal);
    } else {
      output[key] = sourceVal;
    }
  }

  return output as T & S;
}

