  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

const FIELDS: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function clamp(value: number, min: number, max: number, label: string): number {
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of range [${min},${max}] for field "${label}"`);
  return value;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new RangeError(`Invalid step value "${stepStr}" for field "${field}"`);

    const [from, to] = left === "*" ? [min, max] : left.split("-").map(Number);
    if (isNaN(from) || isNaN(to))
      throw new SyntaxError(`Invalid step expression "${segment}" for field "${field}"`);

    clamp(from, min, max, field);
    clamp(to, min, max, field);

    const values: number[] = [];
    for (let i = from; i <= to; i += step) values.push(i);
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const from = clamp(parseInt(startStr, 10), min, max, field);
    const to   = clamp(parseInt(endStr,   10), min, max, field);
    return range(from, to);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value))
    throw new SyntaxError(`Invalid value "${segment}" for field "${field}"`);
  return [clamp(value, min, max, field)];
}

function parseField(expr: string, field: CronField): number[] {
  const seen = new Set<number>();
  for (const segment of expr.split(",")) {
    for (const value of parseSegment(segment.trim(), field)) {
      seen.add(value);
    }
  }
  return [...seen].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new SyntaxError(`Expected 5 fields, got ${parts.length}: "${expression}"`);

  return Object.fromEntries(
    FIELDS.map((field, i) => [field, parseField(parts[i], field)])
  ) as CronExpression;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

export default function deepMerge<T extends PlainObject>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key as keyof typeof source];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: [keyof CronFields, FieldConfig][] = [
  ["minute",     { min: 0,  max: 59 }],
  ["hour",       { min: 0,  max: 23 }],
  ["dayOfMonth", { min: 1,  max: 31 }],
  ["month",      { min: 1,  max: 12 }],
  ["dayOfWeek",  { min: 0,  max: 6  }],
];

function expandRange(start: number, end: number, step: number, min: number, max: number): number[] {
  if (start < min || end > max || start > end) {
    throw new RangeError(`Range ${start}-${end} is out of bounds [${min}, ${max}]`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, { min, max }: FieldConfig): number[] {
  // Wildcard: * or */step
  if (segment === "*") {
    return expandRange(min, max, 1, min, max);
  }

  // Step with wildcard: */step
  const wildcardStep = segment.match(/^\*\/(\d+)$/);
  if (wildcardStep) {
    const step = parseInt(wildcardStep[1], 10);
    if (step < 1) throw new RangeError(`Step value must be >= 1, got ${step}`);
    return expandRange(min, max, step, min, max);
  }

  // Range with optional step: start-end or start-end/step
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    const step  = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;
    if (step < 1) throw new RangeError(`Step value must be >= 1, got ${step}`);
    return expandRange(start, end, step, min, max);
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    if (value < min || value > max) {
      throw new RangeError(`Value ${value} is out of bounds [${min}, ${max}]`);
    }
    return [value];
  }

  throw new SyntaxError(`Invalid cron segment: "${segment}"`);
}

function parseField(field: string, config: FieldConfig): number[] {
  const parts = field.split(",");
  const seen  = new Set<number>();
  const values: number[] = [];

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new SyntaxError(`Empty segment in field: "${field}"`);
    for (const v of parseSegment(trimmed, config)) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [name, config] = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], config);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(obj: NestedObject, prefix = "", result: FlatObject = {}): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | unknown[];
    }
  }

  return result;
}

