interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 6],
};

function rangeArray(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(token: string, min: number, max: number): number[] {
  // Comma-separated list
  if (token.includes(",")) {
    const values = token.split(",").flatMap((t) => parseField(t.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (token === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or start-end/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
      start = clamp(s, min, max);
      end = clamp(e, min, max);
      if (start > end) throw new RangeError(`Invalid range: "${rangePart}"`);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      end = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new RangeError(`Invalid range: "${token}"`);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(token, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron token: "${token}"`);
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];
  const result = {} as CronExpression;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fields[i], min, max);
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expr: string, min: number, max: number): number[] {
  const values = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      range(min, max).forEach(v => values.add(v));
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      for (let v = min; v <= max; v += step) values.add(v);
    } else if (part.includes("/")) {
      const [rangePart, stepStr] = part.split("/");
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = endStr !== undefined ? parseInt(endStr, 10) : max;
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${part}`);
      if (start < min || end > max || start > end) throw new Error(`Out-of-range: ${part} (allowed ${min}-${max})`);
      for (let v = start; v <= end; v += step) values.add(v);
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${part}`);
      if (start < min || end > max || start > end) throw new Error(`Out-of-range: ${part} (allowed ${min}-${max})`);
      range(start, end).forEach(v => values.add(v));
    } else {
      const n = parseInt(part, 10);
      if (isNaN(n)) throw new Error(`Invalid value: ${part}`);
      if (n < min || n > max) throw new Error(`Out-of-range: ${n} (allowed ${min}-${max})`);
      values.add(n);
    }
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return Object.fromEntries(
    fields.map((field, i) => {
      const [min, max] = FIELD_RANGES[field];
      return [field, parseField(exprs[i], min, max)];
    })
  ) as CronFields;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, readonly [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   7], // 0 and 7 both represent Sunday
} as const;

function range(start: number, end: number): number[] {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Comma-separated list — recurse per part
  if (segment.includes(",")) {
    const seen = new Set<number>();
    for (const part of segment.split(",")) {
      for (const v of parseSegment(part.trim(), min, max)) seen.add(v);
    }
    return [...seen].sort((a, b) => a - b);
  }

  // Step value: */n or start/n or start-end/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let start: number;
    let end: number;

    if (base === "*") {
      [start, end] = [min, max];
    } else if (base.includes("-")) {
      const [s, e] = base.split("-").map(Number);
      [start, end] = [s, e];
    } else {
      start = parseInt(base, 10);
      end = max;
    }

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid step base: ${base}`);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    return range(start, end);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${segment}`);
  return [value];
}

function validateValues(values: number[], min: number, max: number, field: string): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
  return values;
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${parts.length}`);
  }

  const fields = Object.keys(FIELD_RANGES) as FieldName[];
  const result = {} as CronFields;

  for (let i = 0; i < fields.length; i++) {
    const name = fields[i];
    const [min, max] = FIELD_RANGES[name];
    const raw = parseSegment(parts[i], min, max);
    result[name] = validateValues(raw, min, max, name);
  }

  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  if (typeof value !== "object" || value === null) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  const result = { ...target } as PlainObject;

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

